import type { Plugin } from 'vite'
import fs from 'node:fs'
import path from 'node:path'

/**
 * Vite plugin that serves LLM-friendly .md files, llms.txt, and
 * llms-full.txt during development.
 *
 * In production these files are generated by scripts/gen-llms-txt.ts
 * and served as static files from the site/ directory.
 */
export function llmsTxtPlugin(): Plugin {
  let projectRoot: string

  return {
    name: 'naive-ui-llms-txt',
    configResolved(config) {
      projectRoot = config.root
    },
    configureServer(server) {
      server.middlewares.use((req, res, next) => {
        const url = req.url || ''

        // Handle /llms.txt
        if (url === '/llms.txt') {
          const content = generateLlmsTxt(projectRoot)
          res.setHeader('Content-Type', 'text/plain; charset=utf-8')
          res.end(content)
          return
        }

        // Handle /llms-full.txt
        if (url === '/llms-full.txt') {
          const content = generateLlmsFullTxt(projectRoot)
          res.setHeader('Content-Type', 'text/plain; charset=utf-8')
          res.end(content)
          return
        }

        // Handle flat paths: /docs/*.md, /components/*.md, /zh-docs/*.md, /zh-components/*.md
        const flatMatch = url.match(
          /^\/(docs|components|zh-docs|zh-components)\/([a-z0-9-]+)\.md$/
        )
        if (flatMatch) {
          const [, dir, slug] = flatMatch
          return serveMd(res, projectRoot, dir, slug, url)
        }

        // Handle SPA-style paths: /{lang}/{theme}/(docs|components)/{slug}.md
        // e.g. /zh-CN/os-theme/components/button.md
        //      /en-US/os-theme/docs/introduction.md
        const spaMatch = url.match(
          /^\/(en-US|zh-CN)\/[^/]+\/(docs|components)\/([a-z0-9-]+)\.md$/
        )
        if (spaMatch) {
          const [, lang, category, slug] = spaMatch
          const dir
            = lang === 'zh-CN'
              ? category === 'components'
                ? 'zh-components'
                : 'zh-docs'
              : category === 'components'
                ? 'components'
                : 'docs'
          return serveMd(res, projectRoot, dir, slug, url)
        }

        next()
      })
    }
  }
}

function serveMd(
  res: import('node:http').ServerResponse,
  projectRoot: string,
  dir: string,
  slug: string,
  url: string
): void {
  const filePath = resolveSourceMd(projectRoot, dir, slug)

  if (filePath && fs.existsSync(filePath)) {
    const raw = fs.readFileSync(filePath, 'utf-8')
    const cleaned = cleanMarkdown(raw, filePath)
    res.setHeader('Content-Type', 'text/markdown; charset=utf-8')
    res.end(cleaned)
    return
  }

  res.statusCode = 404
  res.end(`Not found: ${url}`)
}

// ---------------------------------------------------------------------------
// Route mapping
// ---------------------------------------------------------------------------

interface RouteEntry {
  routePath: string
  filePath: string
  category: 'docs' | 'components'
  locale: 'en' | 'zh'
}

let routeCache: RouteEntry[] | null = null

function getRoutes(projectRoot: string): RouteEntry[] {
  if (routeCache)
    return routeCache

  const routesFile = fs.readFileSync(
    path.resolve(projectRoot, 'demo/routes/routes.js'),
    'utf-8'
  )

  const routes: RouteEntry[] = []
  const blocks = [
    { name: 'enDocRoutes', category: 'docs' as const, locale: 'en' as const },
    { name: 'zhDocRoutes', category: 'docs' as const, locale: 'zh' as const },
    {
      name: 'enComponentRoutes',
      category: 'components' as const,
      locale: 'en' as const
    },
    {
      name: 'zhComponentRoutes',
      category: 'components' as const,
      locale: 'zh' as const
    }
  ]

  for (const block of blocks) {
    const blockRegex = new RegExp(
      `export const ${block.name}\\s*=\\s*\\[([\\s\\S]*?)\\n\\]`,
      'm'
    )
    const blockMatch = routesFile.match(blockRegex)
    if (!blockMatch)
      continue

    const importRegex = /path:\s*'([^']+)'[\s\S]*?import\(\s*'([^']+)'\s*\)/g
    let match: RegExpExecArray | null = importRegex.exec(blockMatch[1])

    while (match !== null) {
      const importPath = match[2]
      const resolvedImport = path.resolve(
        projectRoot,
        'demo/routes',
        importPath
      )

      if (importPath.endsWith('.vue')) {
        // .vue wrappers may import a .md file — extract it
        const mdPath = extractMdFromVue(resolvedImport)
        if (mdPath) {
          routes.push({
            routePath: match[1],
            filePath: mdPath,
            category: block.category,
            locale: block.locale
          })
        }
        match = importRegex.exec(blockMatch[1])
        continue
      }

      routes.push({
        routePath: match[1],
        filePath: resolvedImport,
        category: block.category,
        locale: block.locale
      })
      match = importRegex.exec(blockMatch[1])
    }
  }

  routeCache = routes
  return routes
}

/**
 * Read a .vue wrapper file and extract the first `.md` import path.
 * e.g. `import Changelog from '../../../../../CHANGELOG.en-US.md'`
 */
function extractMdFromVue(vuePath: string): string | null {
  if (!fs.existsSync(vuePath))
    return null
  const content = fs.readFileSync(vuePath, 'utf-8')
  const mdImport = content.match(/import\s+\w+\s+from\s+['"]([^'"]+\.md)['"]/i)
  if (!mdImport)
    return null
  return path.resolve(path.dirname(vuePath), mdImport[1])
}

function resolveSourceMd(
  projectRoot: string,
  dir: string,
  slug: string
): string | null {
  const routes = getRoutes(projectRoot)

  const locale = dir.startsWith('zh') ? 'zh' : 'en'
  const category = dir.includes('component') ? 'components' : 'docs'

  const entry = routes.find(
    r =>
      r.routePath === slug && r.locale === locale && r.category === category
  )
  return entry?.filePath ?? null
}

// ---------------------------------------------------------------------------
// Markdown cleaning (same logic as scripts/gen-llms-txt.ts)
// ---------------------------------------------------------------------------

function cleanMarkdown(content: string, sourceFilePath: string): string {
  let cleaned = content

  cleaned = cleaned.replace(/<!--[\s\S]*?-->\n?/g, '')
  cleaned = expandDemoBlocks(cleaned, sourceFilePath)
  cleaned = cleaned.replace(/```component\n[\s\S]*?```\n?/g, '')
  cleaned = removeHtmlBlocks(cleaned)
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n')
  cleaned = `${cleaned.trim()}\n`

  return cleaned
}

function expandDemoBlocks(content: string, sourceFilePath: string): string {
  const sourceDir = path.dirname(sourceFilePath)

  return content.replace(
    /```demo\n([\s\S]*?)```\n?/g,
    (_match, fileList: string) => {
      const filenames = fileList
        .trim()
        .split('\n')
        .map((f: string) => f.trim())
        .filter(Boolean)

      const expanded: string[] = []

      for (const filename of filenames) {
        const demoFileName = filename.replace(/\.vue$/, '.demo.vue')
        const demoFilePath = path.join(sourceDir, demoFileName)

        if (!fs.existsSync(demoFilePath))
          continue

        const demoContent = fs.readFileSync(demoFilePath, 'utf-8')

        const mdMatch = demoContent.match(/<markdown>([\s\S]*?)<\/markdown>/)
        const markdownPart = mdMatch ? mdMatch[1].trim() : ''

        const codePart = demoContent
          .replace(/<markdown>[\s\S]*?<\/markdown>\n?/, '')
          .trim()

        if (markdownPart)
          expanded.push(markdownPart)
        if (codePart)
          expanded.push(`\`\`\`vue\n${codePart}\n\`\`\``)
        expanded.push('')
      }

      return expanded.join('\n')
    }
  )
}

function removeHtmlBlocks(content: string): string {
  const lines = content.split('\n')
  const result: string[] = []
  let depth = 0
  let inCodeFence = false

  for (const line of lines) {
    const trimmed = line.trim()

    // Track fenced code blocks — never strip HTML inside them
    if (trimmed.startsWith('```')) {
      inCodeFence = !inCodeFence
      result.push(line)
      continue
    }

    if (inCodeFence) {
      result.push(line)
      continue
    }

    const openTags
      = trimmed.match(/<[a-zA-Z][a-zA-Z0-9-]*(?:\s[^>]*)?(?<!\/)\s*>/g) || []
    const closeTags = trimmed.match(/<\/[a-zA-Z][a-zA-Z0-9-]+\s*>/g) || []
    const selfClosing
      = trimmed.match(/<[a-zA-Z][a-zA-Z0-9-]*(?:\s[^>]*)?\s*\/>/g) || []

    if (depth > 0) {
      depth += openTags.length - closeTags.length
      continue
    }

    if (/^\s*<[a-zA-Z]/.test(line)) {
      const netOpen = openTags.length - closeTags.length
      if (netOpen > 0) {
        depth = netOpen
        continue
      }
      else if (
        selfClosing.length > 0
        || (openTags.length > 0 && closeTags.length >= openTags.length)
      ) {
        continue
      }
    }

    result.push(line)
  }

  return result.join('\n')
}

// ---------------------------------------------------------------------------
// llms.txt / llms-full.txt generation
// ---------------------------------------------------------------------------

function generateLlmsTxt(projectRoot: string): string {
  const routes = getRoutes(projectRoot)
  const enRoutes = routes.filter(r => r.locale === 'en')
  const lines: string[] = []

  lines.push('# Naive UI')
  lines.push('')
  lines.push(
    '> A Vue 3 Component Library. Fairly Complete, Theme Customizable, Uses TypeScript, Fast.'
  )
  lines.push('')

  for (const category of ['docs', 'components'] as const) {
    const group = enRoutes.filter(r => r.category === category)
    if (group.length === 0)
      continue

    lines.push(`## ${category === 'docs' ? 'Docs' : 'Components'}`)
    lines.push('')

    for (const route of group) {
      const title = route.routePath
        .split('-')
        .map(w => w.charAt(0).toUpperCase() + w.slice(1))
        .join(' ')
      const dir = category === 'docs' ? 'docs' : 'components'
      lines.push(`- [${title}](/en-US/os-theme/${dir}/${route.routePath}.md)`)
    }
    lines.push('')
  }

  return lines.join('\n')
}

function generateLlmsFullTxt(projectRoot: string): string {
  const routes = getRoutes(projectRoot)
  const enRoutes = routes.filter(r => r.locale === 'en')
  const parts: string[] = []

  for (const route of enRoutes) {
    if (!fs.existsSync(route.filePath))
      continue
    const raw = fs.readFileSync(route.filePath, 'utf-8')
    const cleaned = cleanMarkdown(raw, route.filePath)
    const dir = route.category === 'docs' ? 'docs' : 'components'
    parts.push(
      `---\nurl: /en-US/os-theme/${dir}/${route.routePath}.md\n---\n\n${cleaned}`
    )
  }

  return parts.join('\n')
}
